#import "WBPurchaseSectionView.h"
#import "WBWebViewController.h"
#import "WBProductModel.h"

@interface WBPurchaseSectionView ()

@property(nonatomic, strong) UIButton *purchaseButton;
@property(nonatomic, strong) UILabel *renewTipLabel;
@property(nonatomic, strong) YYLabel *agreementLabel;

@end

@implementation WBPurchaseSectionView

- (instancetype)initWithFrame:(CGRect)frame {
    if (self = [super initWithFrame:frame]) {
        [self addAllSubviews];
        [self addAllConstraints];
    }
    return self;
}

- (void)addAllSubviews {
    [self addSubview:self.purchaseButton];
    [self addSubview:self.renewTipLabel];
    [self addSubview:self.agreementLabel];
}

- (void)addAllConstraints {
    [self.purchaseButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self);
        make.centerX.equalTo(self);
        make.height.mas_equalTo(WBRpt(54));
        make.width.mas_equalTo(WBRpt(315));
    }];

    [self.agreementLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self);
        make.top.equalTo(self.renewTipLabel.mas_bottom).offset(WBRpt(4));
        make.width.mas_equalTo(ZOOM(300));
    }];

    [self.renewTipLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self);
        make.top.equalTo(self.purchaseButton.mas_bottom).offset(WBRpt(6));
        make.left.greaterThanOrEqualTo(self).offset(ZOOM(16));
        make.right.lessThanOrEqualTo(self).offset(ZOOM(-16));
    }];
}


#pragma mark - SetEvent

- (void)setNeedsRefreshUI {
    // 强制清空当前显示内容
    [self.purchaseButton setAttributedTitle:nil forState:UIControlStateNormal];
    [self.purchaseButton setTitle:nil forState:UIControlStateNormal];

    // 重新触发商品模型设置
    if (self.productModel) {
        [self setProductModel:self.productModel];
    }
}

- (void)setProductModel:(WBProductModel *)productModel {
    _productModel = productModel;

    CGFloat discountedPrice = productModel.discountedPrice;

    // 配置按钮基础属性
    self.purchaseButton.titleLabel.numberOfLines = 0; // 允许多行
    self.purchaseButton.titleLabel.textAlignment = NSTextAlignmentCenter;

    if (productModel.displayPriceText.length || discountedPrice > 0) {
        NSString *priceStr = nil;
        if (productModel.displayPriceText.length) {
            priceStr = productModel.displayPriceText;
        } else {
            priceStr = [NSString stringWithFormat:@"%@%g", productModel.currencySymbol, discountedPrice];
        }

        NSMutableAttributedString *attributedString = [[NSMutableAttributedString alloc] init];

        NSDictionary *titleAttributes = @{
            NSFontAttributeName: [UIFont fontWithName:@"PingFangSC-Semibold" size:ZOOM(18)],
            NSForegroundColorAttributeName: WBColorHex(0xFFFFFF)
        };
        NSAttributedString *titlePart = [[NSAttributedString alloc] initWithString:NSLocalizedString(@"立即支付\n", nil) attributes:titleAttributes];
        [attributedString appendAttributedString:titlePart];

        NSDictionary *priceAttributes = @{
            NSFontAttributeName: [UIFont fontWithName:@"PingFangSC-Regular" size:ZOOM(12)],
            NSForegroundColorAttributeName: WBColorHex(0xFFFFFF)
        };
        NSAttributedString *pricePart = [[NSAttributedString alloc] initWithString:priceStr attributes:priceAttributes];
        [attributedString appendAttributedString:pricePart];

        NSMutableParagraphStyle *paragraphStyle = [[NSMutableParagraphStyle alloc] init];
        paragraphStyle.alignment = NSTextAlignmentCenter;
        paragraphStyle.lineSpacing = ZOOM(0);
        [attributedString addAttribute:NSParagraphStyleAttributeName
                                value:paragraphStyle
                                range:NSMakeRange(0, attributedString.length)];

        [self.purchaseButton setAttributedTitle:attributedString forState:UIControlStateNormal];
    } else {
        [self.purchaseButton setAttributedTitle:nil forState:UIControlStateNormal];
        [self.purchaseButton setTitle:NSLocalizedString(@"立即支付", nil) forState:UIControlStateNormal];
    }

    // 添加按钮内容边距
    self.purchaseButton.contentEdgeInsets = UIEdgeInsetsMake(8, 0, 8, 0);
}


#pragma mark - lazy load

- (UIButton *)purchaseButton {
    if (!_purchaseButton) {
        _purchaseButton = [UIButton buttonWithType:UIButtonTypeCustom];
        _purchaseButton.titleLabel.numberOfLines = 0;
        _purchaseButton.titleLabel.textAlignment = NSTextAlignmentCenter;
        [_purchaseButton setTitle:NSLocalizedString(@"立即支付", nil) forState:UIControlStateNormal];
        [_purchaseButton setTitleColor:WBColorHex(0xFFFFFF) forState:UIControlStateNormal];
        _purchaseButton.titleLabel.font = WBPrimaryBoldFont(18);
        _purchaseButton.layer.cornerRadius = WBRpt(27);
        _purchaseButton.backgroundColor = GreenColor_g;
        _purchaseButton.titleLabel.lineBreakMode = NSLineBreakByWordWrapping; // 自动换行
    }
    return _purchaseButton;
}

