            NSForegroundColorAttributeName: WBColorHex(0x333333),
            NSUnderlineStyleAttributeName: @(NSUnderlineStyleSingle),
            NSUnderlineColorAttributeName: WBColorHex(0x333333)
        }.mutableCopy;

        // 高亮设置（保持下划线）
        YYTextHighlight *highlight = [[YYTextHighlight alloc] init];
        [highlight setAttributes:@{
            NSUnderlineStyleAttributeName: @(NSUnderlineStyleSingle),
            NSUnderlineColorAttributeName: WBColorHex(0x333333)
        }];
        highlight.tapAction = ^(UIView *containerView, NSAttributedString *text, NSRange range, CGRect rect) {
            NSString *tappedText = [text.string substringWithRange:range];
            BOOL isTerm = [tappedText isEqualToString:termKey];

            NSURL *targetURL = isTerm ?
                [NSURL URLWithString:WBSettingManager.sharedManager.UserTermURL] :
                [NSURL URLWithString:WBSettingManager.sharedManager.PrivacyURL];

            WBWebViewController *webVC = [[WBWebViewController alloc] initWithURL:targetURL];
            webVC.title = isTerm ?
                NSLocalizedString(@"服务协议", @"Terms of Service") :
                NSLocalizedString(@"隐私政策", @"Privacy Policy");

            [self.viewController.navigationController pushViewController:webVC animated:YES];
        };
        linkAttr[YYTextHighlightAttributeName] = highlight;

        // 构建富文本
        NSMutableAttributedString *attrString = [[NSMutableAttributedString alloc] initWithString:agreement attributes:attr];

        // 动态添加链接范围
