    }
    return _agreementLabel;
}

- (UILabel *)renewTipLabel {
    if (_renewTipLabel == nil) {
        _renewTipLabel = [[UILabel alloc] init];
        _renewTipLabel.text = NSLocalizedString(@"续订商品，可随时取消", nil);
        _renewTipLabel.textColor = WBColorHex(0x666666);
        _renewTipLabel.font = WBPrimaryBoldFont(13);
        _renewTipLabel.textAlignment = NSTextAlignmentCenter;
        _renewTipLabel.numberOfLines = 0;
    }
    return _renewTipLabel;
